  1→import { useMemo, useRef } from 'react';
  2→import { TOOLS } from './tools';
  3→import { createWallDrawHandler } from './handlers/wallDrawHandler';
  4→import { createSelectHandler } from './handlers/selectHandler';
  5→import { createDimensionPlaceHandler } from './handlers/dimensionPlaceHandler';
  6→import { createDoorPlaceHandler } from './handlers/doorPlaceHandler';
  7→import { createWindowPlaceHandler } from './handlers/windowPlaceHandler';
  8→import { createColumnPlaceHandler } from './handlers/columnPlaceHandler';
  9→import { createRoomPlaceHandler } from './handlers/roomPlaceHandler';
 10→import { createBeamPlaceHandler } from './handlers/beamPlaceHandler';
 11→import { createSlabPlaceHandler } from './handlers/slabPlaceHandler';
 12→import { createStairPlaceHandler } from './handlers/stairPlaceHandler';
 13→import { createSectionPlaceHandler } from './handlers/sectionPlaceHandler';
 14→import { createLandingPlaceHandler } from './handlers/landingPlaceHandler';
 15→import { createFixturePlaceHandler } from './handlers/fixturePlaceHandler';
 16→import { createRailingPlaceHandler } from './handlers/railingPlaceHandler';
 17→import { createElevationSelectHandler } from './handlers/elevationSelectHandler';
 18→import { createRoofSelectHandler } from './handlers/roofSelectHandler';
 19→import { createRoofParapetPlaceHandler } from './handlers/roofParapetPlaceHandler';
 20→import { createRoofDrainPlaceHandler } from './handlers/roofDrainPlaceHandler';
 21→import { createRoofOpeningPlaceHandler } from './handlers/roofOpeningPlaceHandler';
 22→import { createTrussSelectHandler } from './handlers/trussSelectHandler';
 23→import { createTrussDrawHandler } from './handlers/trussDrawHandler';
 24→
 25→function createReadOnlyHandler() {
 26→  return {
 27→    onMouseDown() {},
 28→    onMouseMove() {},
 29→    onMouseUp() {},
 30→    onDoubleClick() {},
 31→    onKeyDown() {},
 32→    getCursor() {
 33→      return 'default';
 34→    },
 35→  };
 36→}
 37→
 38→export function useEditorTool({ activeTool, dispatch, editorDispatch, project, getFloor, activeFloorId, roofSystem, trussSystems, modelTarget, viewport, snapEnabled, selectedId, selectedType, toolState, viewMode, activePhaseId }) {
 39→  const getFloorRef = useRef(getFloor);
 40→  getFloorRef.current = getFloor;
 41→
 42→  const handler = useMemo(() => {
 43→    if (modelTarget === 'truss') {
 44→      if (viewMode !== 'plan') {
 45→        return createReadOnlyHandler();
 46→      }
 47→
 48→      const trussCtx = {
 49→        dispatch,
 50→        editorDispatch,
 51→        getFloor: (...args) => getFloorRef.current(...args),
 52→        activeFloorId,
 53→        trussSystems,
 54→        viewport,
 55→        selectedId,
 56→        selectedType,
 57→      };
 58→
 59→      switch (activeTool) {
 60→        case TOOLS.TRUSS_DRAW:
 61→          return createTrussDrawHandler(trussCtx);
 62→        case TOOLS.SELECT:
 63→        default:
 64→          return createTrussSelectHandler(trussCtx);
 65→      }
 66→    }
 67→
 68→    if (modelTarget === 'roof') {
 69→      if (viewMode !== 'plan') {
 70→        return createReadOnlyHandler();
 71→      }
 72→
 73→      const roofCtx = {
 74→        dispatch,
 75→        editorDispatch,
 76→        roofSystem,
 77→        viewport,
 78→      };
 79→
 80→      switch (activeTool) {
 81→        case TOOLS.ROOF_PARAPET:
 82→          return createRoofParapetPlaceHandler(roofCtx);
 83→        case TOOLS.ROOF_DRAIN:
 84→          return createRoofDrainPlaceHandler(roofCtx);
 85→        case TOOLS.ROOF_OPENING:
 86→          return createRoofOpeningPlaceHandler(roofCtx);
 87→        case TOOLS.SELECT:
 88→        default:
 89→          return createRoofSelectHandler(roofCtx);
 90→      }
 91→    }
 92→
 93→    if (viewMode?.startsWith('elevation_')) {
 94→      return createElevationSelectHandler({
 95→        dispatch,
 96→        editorDispatch,
 97→        project,
 98→        getFloor: (...args) => getFloorRef.current(...args),
 99→        activeFloorId,
100→        viewport,
101→        snapEnabled,
102→        viewMode,
103→      });
104→    }
105→
106→    if (viewMode !== 'plan') {
107→      return createReadOnlyHandler();
108→    }
109→
110→    const ctx = {
111→      dispatch, editorDispatch,
112→      getFloor: (...args) => getFloorRef.current(...args),
113→      activeFloorId, viewport, snapEnabled, activePhaseId,
114→    };
115→
116→    switch (activeTool) {
117→      case TOOLS.DIMENSION:
118→        return createDimensionPlaceHandler(ctx);
119→      case TOOLS.WALL:
120→        return createWallDrawHandler(ctx);
121→      case TOOLS.BEAM:
122→        return createBeamPlaceHandler(ctx);
123→      case TOOLS.STAIR:
124→        return createStairPlaceHandler(ctx);
125→      case TOOLS.SECTION:
126→        return createSectionPlaceHandler(ctx);
127→      case TOOLS.SLAB:
128→        return createSlabPlaceHandler(ctx);
129→      case TOOLS.ROOM:
130→        return createRoomPlaceHandler(ctx);
131→      case TOOLS.SELECT:
132→        return createSelectHandler(ctx);
133→      case TOOLS.DOOR:
134→        return createDoorPlaceHandler(ctx);
135→      case TOOLS.WINDOW:
136→        return createWindowPlaceHandler(ctx);
137→      case TOOLS.COLUMN:
138→        return createColumnPlaceHandler(ctx);
139→      case TOOLS.LANDING:
140→        return createLandingPlaceHandler(ctx);
141→      case TOOLS.FIXTURE:
142→        return createFixturePlaceHandler(ctx);
143→      case TOOLS.RAILING:
144→        return createRailingPlaceHandler(ctx);
145→      default:
146→        return null;
147→    }
148→  }, [activeTool, activeFloorId, project, roofSystem, trussSystems, modelTarget, viewport.zoom, snapEnabled, viewMode, activePhaseId, selectedId, selectedType]);
149→
150→  return {
151→    onMouseDown: (modelPos, e) => handler?.onMouseDown?.(modelPos, e, toolState),
152→    onMouseMove: (modelPos, e) => handler?.onMouseMove?.(modelPos, e, toolState, selectedId, selectedType),
153→    onMouseUp: (modelPos, e) => handler?.onMouseUp?.(modelPos, e, toolState),
154→    onDoubleClick: (modelPos, e) => handler?.onDoubleClick?.(modelPos, e, toolState),
155→    onKeyDown: (e) => handler?.onKeyDown?.(e, toolState, selectedId, selectedType),
156→    getCursor: () => handler?.getCursor?.(toolState) || 'default',
157→  };
158→}
