124→export function createSelectHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
125→  return {
126→    onMouseDown(modelPos, e, toolState) {
127→      if (e.button !== 0) return;
128→
129→      const floor = getFloor(activeFloorId);
130→      if (!floor) return;
131→
132→      // Check if clicking a handle
133→      const target = e.target;
134→      if (target.dataset.handle) {
135→        editorDispatch({
136→          type: 'UPDATE_TOOL_STATE',
137→          payload: {
138→            dragging: true,
139→            dragType: 'handle',
140→            handle: target.dataset.handle,
141→            handleIndex: target.dataset.index != null ? Number(target.dataset.index) : null,
142→            startPos: modelPos,
143→          },
144→        });
145→        return;
146→      }
147→
148→      const hit = hitTest(modelPos, floor, SNAP_DISTANCE_PX / viewport.zoom * 2.5);
149→      if (hit) {
150→        editorDispatch({ type: 'SELECT_OBJECT', id: hit.id, objectType: hit.type });
151→        const draggableTypes = new Set(['wall', 'column', 'fixture', 'door', 'window', 'stair', 'sectionCut', 'landing', 'railing']);
152→        if (!draggableTypes.has(hit.type)) return;
153→        editorDispatch({
154→          type: 'UPDATE_TOOL_STATE',
155→          payload: {
156→            dragging: true,
157→            dragType: 'move',
158→            startPos: modelPos,
159→            originalPos: modelPos,
160→          },
161→        });
162→      } else {
163→        editorDispatch({
164→          type: 'UPDATE_TOOL_STATE',
165→          payload: {
166→            dragging: true,
167→            dragType: 'marquee',
168→            startPos: modelPos,
169→            currentPos: modelPos,
170→          },
171→        });
172→      }
173→    },
174→
175→    onMouseMove(modelPos, e, toolState, selectedId, selectedType) {
176→      if (toolState.dragging && toolState.dragType === 'marquee') {
177→        editorDispatch({
178→          type: 'UPDATE_TOOL_STATE',
179→          payload: { currentPos: modelPos },
180→        });
181→        return;
182→      }
183→
184→      if (!toolState.dragging || !selectedId) return;
185→
186→      const floor = getFloor(activeFloorId);
187→      if (!floor) return;
188→      const dx = modelPos.x - toolState.startPos.x;
189→      const dy = modelPos.y - toolState.startPos.y;
190→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
191→
192→      if (selectedType === 'wall') {
193→        const wall = floor.walls.find(w => w.id === selectedId);
194→        if (!wall) return;
195→        const resolved = resolveWallEndpoints(wall, floor.columns || []);
196→
197→        if (toolState.dragType === 'handle') {
198→          const handle = toolState.handle;
199→          const oppositeKey = handle === 'start' ? 'end' : 'start';
200→          const oppositePoint = resolved[oppositeKey];
201→          let nextPoint = modelPos;
202→          let nextAttachment = null;
203→
204→          if (e.shiftKey) {
205→            const dx = modelPos.x - oppositePoint.x;
206→            const dy = modelPos.y - oppositePoint.y;
207→            const angle = Math.atan2(dy, dx);
208→            const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
209→            const len = Math.sqrt(dx * dx + dy * dy);
210→            nextPoint = {
211→              x: oppositePoint.x + Math.cos(snapAngle) * len,
212→              y: oppositePoint.y + Math.sin(snapAngle) * len,
213→            };
214→          } else if (snapEnabled) {
215→            const snapResult = snapWallEndpoint(modelPos, {
216→              walls: floor.walls,
217→              columns: floor.columns || [],
218→              snapDist: snapDistModel,
219→              otherPoint: oppositePoint,
220→              ignoreWallId: wall.id,
221→            });
222→            if (snapResult) {
223→              nextPoint = snapResult.point;
224→              nextAttachment = snapResult.attachment;
225→            }
226→          }
227→
228→          if (distance(nextPoint, oppositePoint) < MIN_WALL_LENGTH) return;
229→
230→          dispatch({
231→            type: 'WALL_UPDATE',
232→            floorId: activeFloorId,
233→            wall: {
234→              id: wall.id,
235→              [handle]: nextPoint,
236→              [`${handle}Attachment`]: nextAttachment,
237→            },
238→          });
239→        } else {
240→          let nextStart = { x: resolved.start.x + dx, y: resolved.start.y + dy };
241→          let nextEnd = { x: resolved.end.x + dx, y: resolved.end.y + dy };
242→          let startAttachment = null;
243→          let endAttachment = null;
244→
245→          if (snapEnabled) {
246→            const startSnap = snapWallEndpoint(nextStart, {
247→              walls: floor.walls,
248→              columns: floor.columns || [],
249→              snapDist: snapDistModel,
250→              otherPoint: nextEnd,
251→              ignoreWallId: wall.id,
252→            });
253→            if (startSnap) {
254→              nextStart = startSnap.point;
255→              startAttachment = startSnap.attachment;
256→            }
257→
258→            const endSnap = snapWallEndpoint(nextEnd, {
259→              walls: floor.walls,
260→              columns: floor.columns || [],
261→              snapDist: snapDistModel,
262→              otherPoint: nextStart,
263→              ignoreWallId: wall.id,
264→            });
265→            if (endSnap) {
266→              nextEnd = endSnap.point;
267→              endAttachment = endSnap.attachment;
268→            }
269→          }
270→
271→          if (distance(nextStart, nextEnd) < MIN_WALL_LENGTH) return;
272→
273→          dispatch({
274→            type: 'WALL_UPDATE',
275→            floorId: activeFloorId,
276→            wall: {
277→              id: wall.id,
278→              start: nextStart,
279→              end: nextEnd,
280→              startAttachment,
281→              endAttachment,
282→            },
283→          });
284→        }
285→        editorDispatch({
286→          type: 'UPDATE_TOOL_STATE',
287→          payload: { startPos: modelPos },
288→        });
289→      } else if (selectedType === 'column') {
290→        const col = (floor.columns || []).find(c => c.id === selectedId);
291→        if (!col) return;
292→        dispatch({
293→          type: 'COLUMN_UPDATE',
294→          floorId: activeFloorId,
295→          column: { id: col.id, x: col.x + dx, y: col.y + dy },
296→        });
297→        editorDispatch({
298→          type: 'UPDATE_TOOL_STATE',
299→          payload: { startPos: modelPos },
300→        });
301→      } else if (selectedType === 'fixture') {
302→        const fixture = (floor.fixtures || []).find(f => f.id === selectedId);
303→        if (!fixture) return;
304→        dispatch({
305→          type: 'FIXTURE_UPDATE',
306→          floorId: activeFloorId,
307→          fixture: { id: fixture.id, x: fixture.x + dx, y: fixture.y + dy },
308→        });
309→        editorDispatch({
310→          type: 'UPDATE_TOOL_STATE',
311→          payload: { startPos: modelPos },
312→        });
313→      } else if (selectedType === 'sectionCut') {
314→        const sectionCut = (floor.sectionCuts || []).find(s => s.id === selectedId);
315→        if (!sectionCut) return;
316→
317→        if (toolState.dragType === 'handle') {
318→          const handle = toolState.handle;
319→          const nextSectionCut = handle === 'start'
320→            ? { ...sectionCut, startPoint: modelPos }
321→            : { ...sectionCut, endPoint: modelPos };
322→
323→          if (distance(nextSectionCut.startPoint, nextSectionCut.endPoint) < MIN_WALL_LENGTH) return;
324→
325→          dispatch({
326→            type: 'SECTION_UPDATE',
327→            floorId: activeFloorId,
328→            sectionCut: nextSectionCut,
329→          });
330→        } else {
331→          dispatch({
332→            type: 'SECTION_UPDATE',
333→            floorId: activeFloorId,
334→            sectionCut: {
335→              id: sectionCut.id,
336→              startPoint: {
337→                x: sectionCut.startPoint.x + dx,
338→                y: sectionCut.startPoint.y + dy,
339→              },
340→              endPoint: {
341→                x: sectionCut.endPoint.x + dx,
342→                y: sectionCut.endPoint.y + dy,
343→              },
344→            },
345→          });
346→          editorDispatch({
347→            type: 'UPDATE_TOOL_STATE',
348→            payload: { startPos: modelPos },
349→          });
350→        }
351→      } else if (selectedType === 'railing') {
352→        const railing = (floor.railings || []).find(r => r.id === selectedId);
353→        if (!railing) return;
354→
355→        if (toolState.dragType === 'handle') {
356→          const handle = toolState.handle;
357→          const nextRailing = handle === 'start'
358→            ? { ...railing, startPoint: modelPos }
359→            : { ...railing, endPoint: modelPos };
360→
361→          if (distance(nextRailing.startPoint, nextRailing.endPoint) < MIN_WALL_LENGTH) return;
362→
363→          dispatch({
364→            type: 'RAILING_UPDATE',
365→            floorId: activeFloorId,
366→            railing: nextRailing,
367→          });
368→        } else {
369→          dispatch({
370→            type: 'RAILING_UPDATE',
371→            floorId: activeFloorId,
372→            railing: {
373→              id: railing.id,
374→              startPoint: {
375→                x: railing.startPoint.x + dx,
376→                y: railing.startPoint.y + dy,
377→              },
378→              endPoint: {
379→                x: railing.endPoint.x + dx,
380→                y: railing.endPoint.y + dy,
381→              },
382→            },
383→          });
384→          editorDispatch({
385→            type: 'UPDATE_TOOL_STATE',
386→            payload: { startPos: modelPos },
387→          });
388→        }
389→      } else if (selectedType === 'beam') {
390→        return;
391→      } else if (selectedType === 'stair') {
392→        const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
393→        if (!stair) return;
394→        dispatch({
395→          type: 'STAIR_UPDATE',
396→          floorId: activeFloorId,
397→          stair: {
398→            id: stair.id,
399→            startPoint: {
400→              x: stair.startPoint.x + dx,
401→              y: stair.startPoint.y + dy,
402→            },
403→          },
404→        });
405→        editorDispatch({
406→          type: 'UPDATE_TOOL_STATE',
407→          payload: { startPos: modelPos },
408→        });
409→      } else if (selectedType === 'landing') {
410→        const landing = (floor.landings || []).find(l => l.id === selectedId);
411→        if (!landing) return;
412→        dispatch({
413→          type: 'LANDING_UPDATE',
414→          floorId: activeFloorId,
415→          landing: {
416→            id: landing.id,
417→            position: {
418→              x: landing.position.x + dx,
419→              y: landing.position.y + dy,
420→            },
421→          },
422→        });
423→        editorDispatch({
424→          type: 'UPDATE_TOOL_STATE',
425→          payload: { startPos: modelPos },
426→        });
427→      } else if (selectedType === 'slab') {
428→        if (toolState.dragType !== 'handle' || toolState.handle !== 'slab-vertex' || toolState.handleIndex == null) {
429→          return;
430→        }
431→        const slab = (floor.slabs || []).find(s => s.id === selectedId);
432→        if (!slab) return;
433→
434→        const boundaryPoints = slab.boundaryPoints.map((point, index) => (
435→          index === toolState.handleIndex ? { x: modelPos.x, y: modelPos.y } : point
436→        ));
437→
438→        dispatch({
439→          type: 'SLAB_UPDATE',
440→          floorId: activeFloorId,
441→          slab: {
442→            id: slab.id,
443→            boundaryPoints,
444→          },
445→        });
446→        editorDispatch({
447→          type: 'UPDATE_TOOL_STATE',
448→          payload: { startPos: modelPos },
449→        });
450→      } else if (selectedType === 'door' || selectedType === 'window') {
451→        // Slide along parent wall
452→        const items = selectedType === 'door' ? floor.doors : floor.windows;
453→        const item = items.find(i => i.id === selectedId);
454→        if (!item) return;
455→
456→        const wall = floor.walls.find(w => w.id === item.wallId);
457→        if (!wall) return;
458→
459→        const newOffset = projectPointOnWall(wall, modelPos);
460→        const clampedOffset = clampWallOpeningOffset(wallLength(wall), item.width, newOffset);
461→
462→        const updateType = selectedType === 'door' ? 'DOOR_UPDATE' : 'WINDOW_UPDATE';
463→        dispatch({
464→          type: updateType,
465→          floorId: activeFloorId,
466→          [selectedType]: { id: item.id, offset: clampedOffset },
467→        });
468→
469→        editorDispatch({
470→          type: 'UPDATE_TOOL_STATE',
471→          payload: { startPos: modelPos },
472→        });
473→      }
